"""
MKT Christ Commentary — Psalm 136 (26 verses — the Great Hallel)
Run: python3 scripts/zc-christ-psalm-136.py
Key decisions:
- The refrain 'his steadfast love endures forever' (kî leʿolam hasdo) repeated
  26x is the Christological anchor: John 13:1 'loved to the end'; Rom 8:39
  nothing separates from love of God in Christ Jesus
- v1-3 LORD / God-above-gods / Lord-above-lords → Rev 19:16 Lord of lords
  applied to Christ
- v4 'alone performs great wonders' → Acts 2:22 Jesus accredited by signs/wonders
- v23 'remembered us when we were brought low' → Luke 23:42 thief's cry 'remember me'
- v25 food for every living thing → John 6:35 bread of life
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent


def load_comm(layer, book):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}


def save_comm(layer, book, data):
    p = ROOT / "data" / "commentary" / layer / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=2))


def merge_comm(existing, new_data):
    # INTENT: Write only absent keys — safe to re-run after manual edits.
    # CHANGE? If psalms.json schema changes, update merge_comm and PSALMS below.
    # VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/
    #   psalms.json')); print('136 v23:',d.get('136',{}).get('23','MISSING')[:60])"
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, text in verses.items():
            existing[ch].setdefault(v, text)


# Every verse in Psalm 136 has the same second half: "for his steadfast love endures forever."
# Each entry traces what the stated act of God means for Christ.
PSALMS = {
    "136": {
        "1": "<p>\"Give thanks to the LORD, for he is good — for his <strong>steadfast love endures forever</strong>\" — the Great Hallel opens with the foundational claim: YHWH is good, and his <em>hesed</em> is permanent. The 26-fold refrain (<em>kî leʿolam ḥasdô</em>) is the heartbeat of the psalm and the heartbeat of the gospel. John 13:1: \"having loved his own who were in the world, <strong>he loved them to the end</strong> (<em>eis telos</em>).\" Romans 8:39: \"nothing in all creation will be able to separate us from the love of God that is in Christ Jesus our Lord.\" The steadfast love that endures forever is the love that Christ demonstrates at the cross — the very end he goes to, and the end that proves the love is permanent.</p>",
        "2": "<p>\"Give thanks to the <strong>God above all gods</strong> — for his steadfast love endures forever\" — YHWH is supreme over every divine competitor. First Corinthians 8:5-6: \"even if there are so-called gods... yet for us there is but one God, the Father, from whom all things came and for whom we live; and there is but one Lord, Jesus Christ, through whom all things came and through whom we live.\" The God-above-all-gods is the Father revealed through the Son — the divine supremacy that is most fully expressed in the Incarnation of the one through whom all things exist.</p>",
        "3": "<p>\"Give thanks to the <strong>Lord who reigns above all lords</strong> — for his steadfast love endures forever\" — the triple ascending title (LORD / God of gods / Lord of lords). Revelation 17:14 and 19:16 both apply this title to Christ: \"<strong>Lord of lords and King of kings</strong>.\" The Great Hallel's climactic divine title is the title the book of Revelation places explicitly on the rider on the white horse who is Christ. The one who is Lord of lords is the one whose steadfast love endures forever.</p>",
        "4": "<p>\"To him who alone performs <strong>great wonders</strong> — for his steadfast love endures forever\" — YHWH as the sole wonder-worker. Acts 2:22: \"Jesus of Nazareth was a man accredited by God to you by <strong>miracles, wonders and signs</strong>, which God did among you through him.\" The wonder-working of YHWH that the psalm celebrates is precisely what the apostles cite as the accreditation of Jesus — the one who alone performs great wonders performs them in and through the incarnate Son. Christ's signs and wonders are YHWH's own works.</p>",
        "5": "<p>\"To him who made the heavens with wisdom — for his steadfast love endures forever\" — creation by divine wisdom. Colossians 1:16-17: \"all things have been created through him and for him. He is before all things, and in him all things hold together.\" Proverbs 8:27-30: divine wisdom present at creation. John 1:3: \"Through him all things were made; without him nothing was made that has been made.\" The wisdom by which the heavens were made is the Logos, the Son, through whom the Father creates — the Creator's love endures forever in the Sustainer who holds all things together.</p>",
        "6": "<p>\"To him who laid the earth out over the waters — for his steadfast love endures forever\" — the ordering of creation from watery chaos. Hebrews 1:10-12 (quoting Ps 102:25-27) addresses the Son: \"In the beginning, Lord, you laid the foundations of the earth, and the heavens are the work of your hands.\" The Creator who laid the earth over the waters is addressed as the Son of God — the steadfast love that shaped the original creation is the same love that will shape the new creation (Rev 21:1).</p>",
        "7": "<p>\"To him who made the great lights — for his steadfast love endures forever\" — the luminaries of creation (Gen 1:14-18). John 1:4-5: \"In him was life, and that life was the light of all mankind. The light shines in the darkness.\" John 8:12: \"I am the <strong>light of the world</strong>.\" The great lights created by YHWH's steadfast love are the type of the true light that came into the world in Christ — the Creator of physical light descends as the Light himself, because his steadfast love endures forever.</p>",
        "8": "<p>\"The sun to govern the day — for his steadfast love endures forever\" — the sun's sovereignty over the day. Malachi 4:2: \"But for you who revere my name, the <strong>sun of righteousness</strong> will rise with healing in its rays.\" Revelation 1:16: the risen Christ's face \"was like the sun shining in all its brilliance.\" The sun that governs the day is the type of the Sun of righteousness who governs the eschatological day — the steadfast love that made the physical sun is the steadfast love that gives the eternal light (Rev 22:5: \"they will not need the light of a lamp or the light of the sun, for the Lord God will give them light\").</p>",
        "9": "<p>\"The moon and stars to govern the night — for his steadfast love endures forever\" — the lesser lights governing the darkness. Revelation 22:5: \"There will be no more night\" in the new creation, because the Lamb is the light. The moon and stars that govern the night are provisional — they will be superseded when the night itself is abolished at Christ's return. The steadfast love that creates light for now is the love that will eliminate the need for that light in the age to come.</p>",
        "10": "<p>\"To him who struck down Egypt by killing their firstborn — for his steadfast love endures forever\" — the first Passover plague. First Corinthians 5:7: \"Christ, our Passover lamb, has been sacrificed.\" The striking of Egypt's firstborn is the judgment that falls on God's enemies — and it is the same judgment that God's own Son absorbs at Calvary. The steadfast love that delivered Israel through the death of Egypt's firstborn is the steadfast love that delivers all humanity through the death of God's own Son. The Great Hallel's celebration of Passover is the template the Lord's Supper interprets.</p>",
        "11": "<p>\"Who led Israel out from among them — for his steadfast love endures forever\" — the Exodus itself. Luke 9:31: Moses and Elijah spoke at the Transfiguration about Christ's \"departure (<em>exodon</em>), which he was about to bring to fulfillment at Jerusalem.\" The leading-out of Israel from Egypt is the prototype of the new Exodus that Christ accomplishes — leading humanity out from the Egypt of sin and death through the sea of baptism into the wilderness of discipleship and toward the promised land of the new creation.</p>",
        "12": "<p>\"With a powerful hand and an arm stretched wide — for his steadfast love endures forever\" — the Exodus power language. Acts 13:17: Paul describes how God \"led them out of Egypt with mighty power.\" In Christ, the powerful hand and outstretched arm are the arms stretched wide on the cross — the most counter-intuitive display of divine power. First Corinthians 1:18: \"the message of the cross is foolishness to those who are perishing, but to us who are being saved it is the power of God.\" The outstretched arm of the Exodus is the outstretched arms of the crucifixion.</p>",
        "13": "<p>\"To him who split the Red Sea apart — for his steadfast love endures forever\" — the sea-division miracle. First Corinthians 10:2: Israel \"was baptized into Moses in the cloud and in the sea.\" Romans 6:3-4: \"all of us who were baptized into Christ Jesus were baptized into his death... we too may live a new life.\" The splitting of the Red Sea is the type of Christian baptism — passing through the waters of death into the freedom of new life. Christ himself passes through the waters of baptism (Matt 3:16) and through the waters of death, splitting open the way to resurrection for all who follow him.</p>",
        "14": "<p>\"Who led Israel safely through its midst — for his steadfast love endures forever\" — the safe passage through the sea. Hebrews 11:29: \"By faith the people passed through the Red Sea as on dry land; but when the Egyptians tried to do so, they were drowned.\" Christ leads his people through every sea of death safely — John 10:28: \"I give them eternal life, and they shall never perish; no one will snatch them out of my hand.\" The safe passage through the sea is the type of the eternal security of all who follow Christ through death into life.</p>",
        "15": "<p>\"And swept Pharaoh and his army into the Red Sea — for his steadfast love endures forever\" — the destruction of the pursuing enemy. Colossians 2:15: \"And having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross.\" Pharaoh and his army swept into the sea are the type of every anti-God power that Christ defeats at the cross and resurrection — the same sea that saves Israel drowns the enemy, and the same death that appears to defeat Christ actually defeats everything that opposes his people.</p>",
        "16": "<p>\"To him who guided his people through the desert — for his steadfast love endures forever\" — the forty-year wilderness guidance. First Corinthians 10:3-4: \"They all ate the same spiritual food and drank the same spiritual drink; for they drank from the spiritual rock that accompanied them, and that rock was Christ.\" The divine guidance through the desert was Christ himself — the preexistent Rock who led, fed, and watered Israel in the wilderness. The steadfast love that guided Israel through the desert is the love of the one who was with them all along.</p>",
        "17": "<p>\"To him who defeated great kings — for his steadfast love endures forever\" — the conquest victories. Revelation 19:16: \"On his robe and on his thigh he has this name written: KING OF KINGS AND LORD OF LORDS.\" Christ is the ultimate great king who defeats all other kings — the conquests of the OT period (Sihon, Og, the kings of Canaan) all foreshadow the eschatological victory of the King of kings who \"must reign until he has put all his enemies under his feet\" (1 Cor 15:25).</p>",
        "18": "<p>\"Who slew renowned kings — for his steadfast love endures forever\" — the defeat of powerful rulers. Philippians 2:10-11: \"that at the name of Jesus every knee should bow, in heaven and on earth and under the earth, and every tongue acknowledge that Jesus Christ is Lord.\" The renowned kings slain in the conquest bow before Christ — the eschatological bowing of every king before the name of Jesus is the fulfillment of every conquest victory the Great Hallel celebrates.</p>",
        "19": "<p>\"Sihon, king of the Amorites — for his steadfast love endures forever\" — the first named king (Num 21:21-30). Each named enemy represents a specific resistance to God's purposes that has been overcome. Christ's cross and resurrection is the definitive overcoming of every specific and named resistance — the powers that crucified him (1 Cor 2:8: \"the rulers of this age... crucified the Lord of glory\") discover that they have only accomplished his victory. Sihon and all his like ultimately bow before the crucified and risen Lord.</p>",
        "20": "<p>\"And Og, king of Bashan — for his steadfast love endures forever\" — the second named king, the last of the Rephaim giants (Deut 3:11). The Og-and-Sihon victory pair appears repeatedly in Israel's liturgy as the paradigm of divine power defeating the seemingly indestructible. Christ defeats what seemed indestructible — not human giants but the giants of sin, death, and the curse. Hebrews 2:14-15: \"by his death he might break the power of him who holds the power of death — that is, the devil.\" No giant, human or spiritual, withstands the steadfast love of God in Christ.</p>",
        "21": "<p>\"Who gave their land as an inheritance — for his steadfast love endures forever\" — the land-gift. Hebrews 4:8-9: \"For if Joshua had given them rest, God would not have spoken later about another day. There remains, then, a Sabbath-rest for the people of God.\" The land given as inheritance in the Conquest is the prototype of the eschatological inheritance — not a strip of Middle Eastern territory but the whole renewed earth (Matt 5:5: \"the meek will inherit the earth\") that Christ secures by his death and resurrection.</p>",
        "22": "<p>\"An inheritance given to Israel his servant — for his steadfast love endures forever\" — Israel as YHWH's servant receiving the inheritance. Romans 8:17: \"Now if we are children, then we are heirs — heirs of God and co-heirs with Christ, if indeed we share in his sufferings in order that we may also share in his glory.\" The inheritance given to Israel the servant is now shared with all who are in Christ, the Servant par excellence (Isa 42:1; Phil 2:7) — co-heirs with the one who is heir of all things (Heb 1:2).</p>",
        "23": "<p>\"Who remembered us when we were brought low — for his steadfast love endures forever\" — the divine memory of the humiliated. Luke 23:42: the dying thief cries \"Jesus, <strong>remember me</strong> when you come into your kingdom.\" He uses the exact vocabulary of Psalm 136:23 — \"remember\" at the lowest possible moment. And Christ responds: \"today you will be with me in paradise.\" The divine memory of those brought low, celebrated in the Great Hallel, reaches its most personal expression in Christ's response to the thief who quotes it back in his dying breath.</p>",
        "24": "<p>\"And delivered us from our enemies — for his steadfast love endures forever\" — redemption from enemies. Colossians 2:15: \"And having disarmed the powers and authorities, he made a public spectacle of them, triumphing over them by the cross.\" Luke 1:71-74: Zechariah prophesies that the Messiah will bring \"salvation from our enemies and from the hand of all who hate us... to rescue us from the hand of our enemies, and to enable us to serve him without fear.\" The deliverance from enemies celebrated in the Hallel is the deliverance Christ achieves at the cross — not from political enemies but from sin, death, and the devil.</p>",
        "25": "<p>\"Who provides food for every living thing — for his steadfast love endures forever\" — the universal provision of YHWH. John 6:35: \"I am the <strong>bread of life</strong>. Whoever comes to me will never go hungry, and whoever believes in me will never be thirsty.\" John 6:51: \"I am the living bread that came down from heaven. Whoever eats this bread will live forever.\" The food that YHWH's steadfast love provides for every living creature finds its ultimate form in Christ who feeds the whole world — not manna for a wilderness generation but the living bread that gives eternal life.</p>",
        "26": "<p>\"Give thanks to the <strong>God of heaven</strong> — for his steadfast love endures forever\" — the concluding doxology addressing the highest title: YHWH as the God of heaven. Revelation 11:13; 16:11: \"the God of heaven.\" Christ is the one through whom the God of heaven is accessed (John 14:6: \"No one comes to the Father except through me\") and the one who descended from heaven (John 3:13) and ascended back to heaven (Acts 1:9-11). The God of heaven who fills the Great Hallel with 26 repetitions of his enduring love is the God whose love is most fully expressed in the gift of his Son — and the 26-fold refrain is answered by the eternal song before the Lamb (Rev 5:9-14).</p>"
    }
}


def main():
    existing = load_comm("mkt-christ", "psalms")
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, PSALMS)
    after = sum(len(v) for v in existing.values())
    save_comm("mkt-christ", "psalms", existing)
    print(f"{len(existing)} chapters, {after} verse entries total (+{after - before} new)")
    for v, kw in [("1", "end"), ("3", "Lord of lords"), ("23", "remember"), ("25", "bread")]:
        entry = existing.get("136", {}).get(v, "MISSING")
        print(f"  Ps 136:{v} — {'OK' if kw.lower() in entry.lower() else 'CHECK'}")


if __name__ == "__main__":
    main()
